const verifyBiometric = async (req, res, next) => {
  const { userId, facialData } = req.body;

  try {
    const user = await User.findById(userId);
    const isValid = await faceMatcher.compare(user.facialHash, facialData);

    if (!isValid) {
      return res.status(401).json({ error: 'Verificación facial fallida' });
    }

    req.user = user;
    next();
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
};

const FaceCapture = () => {
  const [image, setImage] = useState(null);
  const [isDetecting, setIsDetecting] = useState(false);

  const handleCapture = async (capturedImage) => {
    setIsDetecting(true);
    try {
      const result = await faceDetectionAPI.verify(capturedImage);
      if (result.confidence > 0.95) {
        await saveBiometricData(result);
        showSuccess('Identidad verificada');
      }
    } finally {
      setIsDetecting(false);
    }
  };

  return <Camera onCapture={handleCapture} />;
};

socket.on('newResponse', async (response) => {
  const updatedStats = await Survey.aggregate([
    { $match: { _id: response.surveyId } },
    { $unwind: '$questions' },
    { $group: {
      _id: '$questions.text',
      average: { $avg: '$responses.value' }
    }}
  ]);

  socket.emit('statsUpdate', updatedStats);
});

const useAccessibility = () => {
  useEffect(() => {
    const handleKeyPress = (e) => {
      if (e.key === 'Tab') {
        document.body.classList.add('keyboard-nav');
      }
    };

    window.addEventListener('keydown', handleKeyPress);
    return () => window.removeEventListener('keydown', handleKeyPress);
  }, []);

  return { skipToContent: () => document.getElementById('main').focus() };
};

const messageReducer = (state, action) => {
  switch (action.type) {
    case 'SEND_MESSAGE':
      return {
        ...state,
        messages: [...state.messages, {
          id: Date.now(),
          text: action.payload,
          timestamp: new Date(),
          status: 'sent'
        }]
      };
    case 'SET_TYPING':
      return { ...state, isTyping: action.payload };
    default:
      return state;
  }
};

